<?php
namespace App\Services;
use App\Core\Database;
use Throwable;
final class SalaryService
{
 public function processDue(): array{$pdo=Database::pdo();$members=$pdo->query("SELECT pgm.* FROM player_gang_members pgm WHERE pgm.status NOT IN ('dismissed','dead') AND (pgm.last_salary_at IS NULL OR pgm.last_salary_at<=DATE_SUB(NOW(),INTERVAL 7 DAY)) ORDER BY pgm.id")->fetchAll();$paid=0;$missed=0;foreach($members as $m){$pdo->beginTransaction();try{$u=$pdo->prepare('SELECT cash FROM users WHERE id=? FOR UPDATE');$u->execute([$m['user_id']]);$cash=(int)$u->fetchColumn();$due=(int)$m['salary_weekly'];$amount=min($cash,$due);$unpaid=$due-$amount;if($amount>0){$pdo->prepare('UPDATE users SET cash=cash-? WHERE id=?')->execute([$amount,$m['user_id']]);$pdo->prepare('UPDATE npcs SET personal_cash=personal_cash+? WHERE id=?')->execute([$amount,$m['npc_id']]);$paid+=$amount;(new EconomyLedgerService())->record('salary_payment',$amount,'Weekly gang salary',['source_type'=>'player','source_id'=>$m['user_id'],'destination_type'=>'gang_member','destination_id'=>$m['id'],'user_id'=>$m['user_id'],'npc_id'=>$m['npc_id'],'gang_member_id'=>$m['id']]);}$pdo->prepare('UPDATE player_gang_members SET unpaid_salary=unpaid_salary+?,morale=GREATEST(0,LEAST(100,morale+?)),loyalty=GREATEST(0,LEAST(100,loyalty+?)),last_salary_at=NOW() WHERE id=?')->execute([$unpaid,$unpaid>0?-8:3,$unpaid>0?-5:2,$m['id']]);$pdo->prepare('INSERT INTO salary_payments(gang_member_id,user_id,amount_due,amount_paid,unpaid_added,processed_at) VALUES(?,?,?,?,?,NOW())')->execute([$m['id'],$m['user_id'],$due,$amount,$unpaid]);if($unpaid>0)$missed++;$pdo->commit();}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();throw $e;}}return ['members_processed'=>count($members),'paid'=>$paid,'missed'=>$missed];}
}
